    expect(typeof result.converged).toBe('boolean');
    expect(result.solvedIr).toHaveProperty('reels');
    expect(result.weightChange).toBeGreaterThanOrEqual(0.1);
    expect(result.weightChange).toBeLessThanOrEqual(10.0);
  });
});

